import os

def parse_theta_results(fname):
    with open(fname) as handle:
        header = next(handle).rstrip().split('\t')
        body = next(handle).rstrip().split('\t')
        nll = float(body[0])
        mu = body[1].split(',')
        mu_normal = float(mu[0])
        mu_tumors = [float(x) for x in mu[1:]]
        c_str = body[2]
        p_str = body[3]
        if len(mu_tumors) == 1:
            # Single tumor: C is colon-separated, p* is comma-separated
            copies = []
            for c in c_str.split(':'):
                try:
                    copies.append(int(c))
                except ValueError:
                    copies.append(None)
            copies = [copies]
            probs = []
            for p in p_str.split(','):
                try:
                    probs.append(float(p))
                except ValueError:
                    probs.append(None)
        else:
            # Multi-tumor: both C and p* are colon-separated groups, each group is comma-separated
            copies = []
            for part in c_str.split(':'):
                sub = []
                for c in part.split(','):
                    try:
                        sub.append(int(c))
                    except ValueError:
                        sub.append(None)
                copies.append(sub)
            probs = []
            for part in p_str.split(':'):
                sub = []
                for p in part.split(','):
                    try:
                        sub.append(float(p))
                    except ValueError:
                        sub.append(None)
                probs.append(sub)
    return {'NLL': nll, 'mu_normal': mu_normal, 'mu_tumors': mu_tumors, 'C': copies, 'p*': probs}

def main():
    # Create a temporary THetA output file with a single tumor example
    sample = (
        "NLL\tmu\tC\tp*\n"
        "12.5\t0.4,0.6\t2:3\t0.1,0.2\n"
    )
    fname = "theta_test.txt"
    with open(fname, "w") as f:
        f.write(sample)

    # Parse the THetA results
    result = parse_theta_results(fname)
    print(result)

    # Clean up
    os.remove(fname)

if __name__ == "__main__":
    main()
